l=q.uC("Hiragana vs Katakana \u2014 \u0915\u0939\u093f\u0932\u0947 \u0915\u0941\u0928 \u092a\u094d\u0930\u092f\u094b\u0917 \u0917\u0930\u094d\u0928\u0947?","Hiragana (\u3072\u3089\u304c\u306a) \u092a\u094d\u0930\u092f\u094b\u0917:\n\u2022 Japanese \u092e\u0942\u0932 \u0936\u092c\u094d\u0926\u0939\u0930\u0942: \u305f\u3079\u308b (taberu = \u0916\u093e\u0928\u0941)\n\u2022 Grammar particles: \u306f\u3001\u304c\u3001\u3092\u3001\u306b\u3001\u3067\n\u2022 Verb endings: \u301c\u307e\u3059\u3001\u301c\u307e\u3057\u305f\n\nKatakana (\u30ab\u30bf\u30ab\u30ca) \u092a\u094d\u0930\u092f\u094b\u0917:\n\u2022 \u0935\u093f\u0926\u0947\u0936\u0940 \u0936\u092c\u094d\u0926\u0939\u0930\u0942: \u30b3\u30fc\u30d2\u30fc (koohii = coffee)\n\u2022 \u0926\u0947\u0936\u0915\u094b \u0928\u093e\u092e: \u30cd\u30d1\u30fc\u30eb (nepaaru = Nepal)\n\u2022 \u0935\u093f\u0926\u0947\u0936\u0940 \u0935\u094d\u092f\u0915\u094d\u0924\u093f\u0915\u094b \u0928\u093e\u092e: \u30e9\u30b8\u30e5 (raju = Raju)\n\u2022 Scientific/Technical terms",B.kg,B.bB)
