B.Nx=new A.cc("Lesson 1 \u2014 \u0938\u094b\u091a\u0915\u094b \u0936\u0915\u094d\u0924\u093f","\u0924\u0947\u0930\u094b \u0938\u094b\u091a \u0928\u0948 \u0924\u0947\u0930\u094b destiny \u0939\u094b","Napoleon Hill \u0932\u0947 500 \u092d\u0928\u094d\u0926\u093e \u092c\u0922\u0940 \u0938\u092b\u0932 \u092e\u093e\u0928\u094d\u091b\u0947\u0939\u0930\u0942\u0915\u094b \u091c\u0940\u0935\u0928 study \u0917\u0930\u094d\u092f\u094b \u0930 \u090f\u0909\u091f\u093e common pattern \u092b\u0947\u0932\u093e\u092f\u094b:\n\n\u0938\u092c\u0948 \u0938\u092b\u0932 \u092e\u093e\u0928\u094d\u091b\u0947\u0939\u0930\u0942\u0915\u094b \u090f\u0909\u091f\u093e \u0915\u0941\u0930\u093e common \u0925\u093f\u092f\u094b \u2014 DEFINITE PURPOSE. \u0938\u094d\u092a\u0937\u094d\u091f \u0932\u0915\u094d\u0937\u094d\u092f\u0964\n\n\u0928\u0947\u092a\u093e\u0932\u092e\u093e \u0939\u093e\u092e\u0940 \u092d\u0928\u094d\u091b\u094c: \u201c\u0915\u0947\u0939\u0940 \u0928 \u0915\u0947\u0939\u0940 \u0939\u094b\u0932\u093e\u0964\u201d \u0924\u0930 \u0927\u0928\u0940 \u092e\u093e\u0928\u094d\u091b\u0947 \u092d\u0928\u094d\u091b: \u201c\u092e\u0948 exactly \u092f\u094b \u091a\u093e\u0939\u0928\u094d\u091b\u0941, \u092f\u094b \u092c\u0947\u0932\u093e \u0938\u092e\u094d\u092e, \u092f\u094b \u0924\u0930\u093f\u0915\u0932\u0947\u0964\u201d\n\n\u0938\u094b\u091a powerful \u091b \u0915\u093f\u0928\u0915\u093f brain \u0932\u0947 real \u0930 imagined \u0915\u0941\u0930\u093e\u092e\u093e farak \u0917\u0930\u094d\u0926\u0948\u0928\u0964 \u0924\u093f\u092e\u0940 \u091c\u0924\u093f \u0938\u094b\u091a\u094d\u091b\u094c, \u0924\u0924\u093f \u0928\u0948 \u0939\u0941\u0928\u094d\u091b\u0964\n\nSubconscious mind \u0915\u0938\u0930\u0940 \u0915\u093e\u092e \u0917\u0930\u094d\u091b?\n\u2022 \u0924\u093f\u092e\u0940\u0932\u0947 \u0938\u094b\u091a\u0947\u0915\u094b \u0915\u0941\u0930\u093e\u0932\u093e\u0908 \u0935\u093e\u0938\u094d\u0924\u0935\u093f\u0915\u0924\u093e \u092e\u093e\u0928\u094d\u091b\n\u2022 \u0924\u094d\u092f\u094b \u0915\u0941\u0930\u093e \u092a\u093e\u0909\u0928\u0947 \u0924\u0930\u093f\u0915\u093e \u0916\u094b\u091c\u094d\u0928 \u0925\u093e\u0932\u094d\u091b\n\u2022 \u0938\u0902\u092f\u094b\u0917\u0939\u0930\u0942 \u092e\u093f\u0932\u093e\u0909\u0928 \u0938\u0939\u092f\u094b\u0917 \u0917\u0930\u094d\u091b\n\n\u0928\u0947\u092a\u093e\u0932 context:\nSEE \u092e\u093e 90% \u0932\u094d\u092f\u093e\u0909\u0928\u0947 \u0935\u093f\u0926\u094d\u092f\u093e\u0930\u094d\u0925\u0940\u0932\u0947 \u0930\u093e\u0924-\u0926\u093f\u0928 \u092f\u0939\u0940 \u0938\u094b\u091a\u094d\u0928\u0947 \u0917\u0930\u0947: \u201c\u092e\u0948 90% \u0932\u094d\u092f\u093e\u0909\u0902\u091b\u0941\u0964\u201d 55% \u0932\u094d\u092f\u093e\u0909\u0928\u0947\u0932\u0947 \u092d\u0928\u094d\u092f\u094b: \u201c\u092a\u093e\u0938 \u092d\u090f \u0939\u0941\u0928\u094d\u091b\u0964\u201d \u0938\u094b\u091a\u0928\u0948 \u0930\u093f\u091c\u0932\u094d\u091f \u0928\u093f\u0930\u094d\u0927\u093e\u0930\u0923 \u0917\u0930\u094d\u0926\u094b\u0930\u0939\u0947\u091b\u0964",B.X7,"\u0906\u091c \u0928\u0948 \u0932\u0947\u0916\u094d\u0928\u0941\u0939\u094b\u0938\u094d: 1 \u092c\u0930\u094d\u0937 \u092a\u091b\u093f \u092e\u0948 \u0915\u0939\u093e\u0901 \u0939\u0941\u0928\u094d\u091b\u0941? Exactly \u0915\u0924\u093f \u0915\u092e\u093e\u0909\u0902\u091b\u0941? Exactly \u0915\u0941\u0928 position \u092e\u093e \u0939\u0941\u0928\u094d\u091b\u0941? \u0932\u0947\u0916\u0940 \u0938\u0915\u0947\u092a\u091b\u093f \u0939\u0930\u0947\u0915 \u092c\u093f\u0939\u093e\u0928 \u092a\u095d\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964","\u0930\u094c\u0924\u0939\u091f\u0915\u094b \u0930\u093e\u091c\u0941\u0932\u0947 Japan \u092e\u093e \u092a\u095d\u094d\u0928 \u091c\u093e\u0928\u0947 goal set \u0917\u0930\u094d\u092f\u094b \u2014 exactly \u0915\u0924\u093f \u092a\u0948\u0938\u093e \u091a\u093e\u0939\u093f\u092f\u094b, \u0915\u0924\u093f \u0926\u093f\u0928\u092e\u093e, \u0915\u0938\u0930\u0940\u0964 \u090f\u0915 \u092c\u0930\u094d\u0937 \u092a\u091b\u093f Japan \u092e\u093e \u0925\u093f\u092f\u094b\u0964 \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u094d\u092a\u0937\u094d\u091f \u092d\u090f\u092a\u091b\u093f \u092c\u093e\u091f\u094b \u092a\u0928\u093f \u0938\u094d\u092a\u0937\u094d\u091f \u0939\u0941\u0928\u094d\u091b\u0964")
B.a_g=s(["Wish \u0930 Desire \u092e\u093e \u0920\u0942\u0932\u094b farak \u091b","Burning desire = \u0915\u0947\u0939\u0940 \u092a\u0928\u093f sacrifice \u0917\u0930\u094d\u0928 \u0924\u092f\u093e\u0930","Desire specific \u0939\u0941\u0928\u0941 \u092a\u0930\u094d\u091b \u2014 vague \u0939\u094b\u0907\u0928","Desire \u0932\u0947 subconscious mind activate \u0917\u0930\u094d\u091b","\u0928\u0947\u092a\u093e\u0932\u092e\u093e wish \u092e\u093e\u0924\u094d\u0930 \u0917\u0930\u0947\u0915\u094b \u0939\u0941\u0902\u0926\u0948\u0928 \u2014 desire \u091a\u093e\u0939\u093f\u0928\u094d\u091b"],t.s)
B.O2=new A.cc("Lesson 2 \u2014 \u0907\u091a\u094d\u091b\u093e\u0915\u094b \u0906\u0917\u094b","Desire \u0928\u0948 \u0938\u092b\u0932\u0924\u093e\u0915\u094b \u092a\u0939\u093f\u0932\u094b \u0915\u0926\u092e \u0939\u094b","Think and Grow Rich \u0915\u094b \u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e important lesson:\n\nOrdinary WISH \u0930 burning DESIRE \u092e\u093e \u0920\u0942\u0932\u094b farak \u091b\u0964\n\nWish: \u201c\u0930\u093e\u092e\u094d\u0930\u094b \u0939\u0941\u0928\u094d\u091b \u092a\u0948\u0938\u093e \u092d\u090f\u0964\u201d\nDesire: \u201c\u092e\u0932\u093e\u0908 \u092a\u0948\u0938\u093e \u091a\u093e\u0939\u093f\u0928\u094d\u091b \u2014 \u0915\u0941\u091a\u0948 \u0917\u0930\u094d\u0928\u0941 \u092a\u0930\u094d\u091b, \u0915\u0947\u0939\u0940 \u092a\u0928\u093f sacrifice \u0917\u0930\u094d\u091b\u0941\u0964\u201d\n\n\u0928\u0947\u092a\u093e\u0932\u092e\u093e \u0909\u0926\u093e\u0939\u0930\u0923:\nWISH: \u201c\u0930\u093e\u092e\u094d\u0930\u094b student \u0939\u0941\u0928\u094d\u091b \u0930\u093e\u092e\u094d\u0930\u094b \u0939\u0941\u0928\u094d\u091b\u0964\u201d \u2014 \u0924\u0930 \u092a\u095d\u094d\u0926\u0948\u0928\u0964\nDESIRE: \u201c\u092e\u0948 topper \u0939\u0941\u0928\u094d\u091b\u0941 \u2014 Dashain \u092e\u093e \u092a\u0928\u093f party \u0928\u0917\u0930\u0940 \u092a\u095d\u094d\u091b\u0941\u0964\u201d \u2014 \u0924\u094d\u092f\u094b distinction \u0932\u094d\u092f\u093e\u0909\u0902\u091b\u0964\n\nDesire \u092c\u0932\u093f\u092f\u094b \u092c\u0928\u093e\u0909\u0928\u0947 5 steps:\n1. Exactly \u0915\u0924\u093f \u092a\u0948\u0938\u093e/marks \u091a\u093e\u0939\u093f\u0928\u094d\u091b \u2014 \u0938\u094d\u092a\u0937\u094d\u091f \u0939\u0941\u0928\u0941 \u092a\u0930\u094d\u091b\n2. \u0924\u094d\u092f\u0938\u0915\u094b \u0932\u093e\u0917\u093f ke sacrifice \u0917\u0930\u094d\u0928 \u0924\u092f\u093e\u0930 \u091b\u094c \u2014 \u0932\u0947\u0916\u094d\u0928\u0941\n3. Deadline set \u0917\u0930\u094d\u0928\u0941 \u2014 exactly \u0915\u0924\u093f \u0924\u093e\u0930\u093f\u0916\u092e\u093e\n4. Plan \u092c\u0928\u093e\u0909\u0928\u0941 \u2014 \u0915\u0938\u0930\u0940 \u092a\u093e\u0909\u0928\u094d\u091b\n5. Harek din bihaan ra raat \u092f\u094b plan \u092a\u095d\u094d\u0928\u0941",B.a_g,"\u0906\u092b\u094d\u0928\u094b \u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e \u0920\u0942\u0932\u094b dream \u0932\u0947\u0916\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964 \u0924\u094d\u092f\u0938\u0915\u094b \u0932\u093e\u0917\u093f ke sacrifice \u0917\u0930\u094d\u0928 \u0924\u092f\u093e\u0930 \u091b\u094c? List \u092c\u0928\u093e\u0909\u0928\u0941 \u2014 \u0906\u091c \u0926\u0947\u0916\u093f sacrifice \u0938\u0941\u0930\u0941 \u0917\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964","\u091a\u093f\u0924\u0935\u0928\u0915\u0940 \u0938\u0941\u0928\u093f\u0924\u093e\u0932\u0947 doctor \u092c\u0928\u094d\u0928\u0947 burning desire \u0930\u093e\u0916\u0947\u0915\u0940 \u0925\u093f\u0908\u0964 Dashain \u092e\u093e \u092a\u0928\u093f party \u0928\u0917\u0930\u0940 \u092a\u095d\u0940\u0964 MBBS \u092a\u093e\u0938\u0940 \u2014 \u0906\u091c Chitwan Hospital \u092e\u093e doctor\u0964 Desire \u0932\u0947 \u0928\u0948 \u091c\u093f\u0924\u0947\u0915\u094b \u0939\u094b\u0964")
B.XS=s(["Brain \u091c\u0938\u094d\u0924\u094b \u0938\u0941\u0928\u094d\u091b, \u0924\u0938\u094d\u0924\u094b believe \u0917\u0930\u094d\u091b","Daily positive affirmation = brain reprogramming","Negative self-talk = negative result","Mirror technique powerful \u091b","21 \u0926\u093f\u0928 daily practice = permanent change"],t.s)
B.Nv=new A.cc("Lesson 3 \u2014 Autosuggestion","\u0906\u092b\u094d\u0928\u094b brain \u0932\u093e\u0908 kasari program \u0917\u0930\u094d\u0928\u0947?","Autosuggestion: \u0906\u092b\u0948\u0932\u093e\u0908 positive \u0915\u0941\u0930\u093e \u0926\u094b\u0939\u094b\u0930\u094d\u092f\u093e\u0909\u0928\u0947 practice\u0964\n\nBrain plastic \u091b \u2014 \u0924\u093f\u092e\u0940 \u091c\u0924\u093f \u092d\u0928\u094d\u091b\u094c, \u0924\u0924\u093f \u0928\u0948 believe \u0917\u0930\u094d\u091b\u0964\n\n\u0928\u0947\u092a\u093e\u0932\u092e\u093e \u0938\u092e\u0938\u094d\u092f\u093e:\nParents \u0932\u0947 \u092d\u0928\u094d\u091b: \u201c\u0924\u093f\u092e\u0940 \u0915\u0947\u0939\u0940 \u0917\u0930\u094d\u0926\u0948\u0928\u094c\u0964\u201d \u092f\u094b negative autosuggestion \u0939\u094b \u2014 damage \u0917\u0930\u094d\u091b\u0964\n\u0924\u093f\u092e\u0940 \u0906\u092b\u0948\u0902 positive autosuggestion \u0917\u0930\u094d\u0928 \u092a\u0930\u094d\u091b\u0964\n\nDaily practice:\n\u2022 \u092c\u093f\u0939\u093e\u0928 \u0909\u0920\u0947\u092a\u091b\u093f mirror \u0939\u0947\u0930\u0940 \u092d\u0928\u094d\u0928\u0941\u0939\u094b\u0938\u094d:\n  \u201c\u092e\u0948 capable \u091b\u0941\u0901, \u092e\u0948 \u0938\u092b\u0932 \u0939\u0941\u0928\u094d\u091b\u0941\u0964\u201d\n\u2022 \u0938\u0941\u0924\u094d\u0928\u0941 \u0905\u0917\u093e\u0921\u093f repeat \u0917\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d:\n  \u201c\u092e\u0948 [goal] \u092a\u093e\u0909\u0901\u091b\u0941 [date] \u0938\u092e\u094d\u092e\u0964\u201d\n\u2022 Negative thought \u0906\u092f\u094b \u092d\u0928\u0947 turant replace \u0917\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d\n\nScience \u0915\u0947 \u092d\u0928\u094d\u091b:\nReticular Activating System (RAS) \u2014 \u0924\u093f\u092e\u0940\u0932\u0947 \u091c\u0938\u0932\u093e\u0908 focus \u0917\u0930\u094d\u091b\u094c, \u0924\u094d\u092f\u0938\u0915\u0948 \u0938\u092e\u094d\u092c\u0928\u094d\u0927\u093f\u0924 \u0915\u0941\u0930\u093e brain \u0932\u0947 \u0926\u0947\u0916\u094d\u0928 \u0925\u093e\u0932\u094d\u091b\u0964\n\nJapan ma padhne Nepali student \u0915\u094b \u0932\u093e\u0917\u093f:\n\u201c\u092e\u0948 Japanese \u0938\u093f\u0915\u094d\u091b\u0941, \u092e\u0948 JLPT N2 \u092a\u093e\u0938 \u0917\u0930\u094d\u091b\u0941\u0964\u201d\n\u092f\u094b daily bhannu \u2014 brain \u0932\u0947 Japanese \u0938\u093f\u0915\u094d\u0928\u0947 \u0938\u092c\u0948 \u0935\u093e\u0924\u093e\u0935\u0930\u0923 notice \u0917\u0930\u094d\u0928 \u0925\u093e\u0932\u094d\u091b\u0964",B.XS,"\u0906\u091c \u0926\u0947\u0916\u093f daily bihaan mirror \u0939\u0947\u0930\u0940 3 \u092a\u0932\u094d\u091f \u092d\u0928\u094d\u0928\u0941\u0939\u094b\u0938\u094d: \u201c\u092e\u0948 [goal] \u092a\u093e\u0909\u0901\u091b\u0941\u0964 \u092e\u0948 capable \u091b\u0941\u0901\u0964\u201d 21 \u0926\u093f\u0928 \u0917\u0930\u093f\u0930\u093e\u0916\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964","\u092a\u094b\u0916\u0930\u093e\u0915\u094b \u092c\u093f\u0915\u094d\u0930\u092e\u0932\u0947 exam \u0905\u0917\u093e\u0921\u093f daily \u092d\u0928\u094d\u091b\u0925\u094d\u092f\u094b: \u201c\u092e\u0948 pass \u0939\u0941\u0928\u094d\u091b\u0941, \u092e\u0948 pass \u0939\u0941\u0928\u094d\u091b\u0941\u0964\u201d Class \u092e\u093e \u0938\u092c\u0948\u0932\u0947 \u0939\u0938\u0947\u0964 \u0924\u0930 distinction \u0932\u094d\u092f\u093e\u092f\u094b \u2014 autosuggestion \u0932\u0947 \u0915\u093e\u092e \u0917\u0930\u094d\u092f\u094b\u0964")
B.a_n=s(["General knowledge \u0932\u0947 school pass \u0917\u0930\u093e\u0909\u0901\u091b","Specialized knowledge \u0932\u0947 paisa \u0915\u092e\u093e\u0909\u0901\u091b","\u090f\u0909\u091f\u093e field \u092e\u093e deepest expert \u092c\u093e\u0909","\u0928\u0947\u092a\u093e\u0932\u092e\u093e specialist \u0915\u094b demand \u092c\u095d\u093f\u0930\u0939\u0947\u0915\u094b \u091b","Continuous learning = continuous earning"],t.s)
B.O1=new A.cc("Lesson 4 \u2014 Specialized Knowledge","General \u0939\u094b\u0907\u0928, Specialist \u092c\u093e\u0909","Napoleon Hill \u0915\u094b important insight:\n\nSchool \u0932\u0947 general knowledge \u0926\u093f\u0928\u094d\u091b\u0964 \u0924\u0930 paisa specialized knowledge \u0932\u0947 \u0926\u093f\u0928\u094d\u091b\u0964\n\n\u0928\u0947\u092a\u093e\u0932\u092e\u093e \u0909\u0926\u093e\u0939\u0930\u0923:\n\u2022 General doctor vs Specialist surgeon \u2014 \u0915\u094b \u092c\u095d\u0940 \u0915\u092e\u093e\u0909\u0902\u091b?\n\u2022 General contractor vs Electrical specialist \u2014 \u0915\u094b \u092c\u095d\u0940 \u092e\u093e\u0917\u093f\u0928\u094d\u091b?\n\u2022 General teacher vs IELTS specialist \u2014 \u0915\u094b \u092c\u095d\u0940 \u092a\u093e\u0909\u0902\u091b?\n\u2022 General IT vs Cybersecurity specialist \u2014 \u0915\u094b \u092c\u095d\u0940 \u0915\u092e\u093e\u0909\u0902\u091b?\n\nSpecialization \u0915\u094b 4 step:\n1. \u0906\u092b\u094d\u0928\u094b interest identify \u0917\u0930\u094d\u0928\u0941 \u2014 \u0915\u0941\u0928 \u0915\u0941\u0930\u093e\u092e\u093e genuine passion \u091b?\n2. \u0924\u094d\u092f\u0938\u092e\u093e deepest knowledge \u0932\u093f\u0928\u0941 \u2014 \u0915\u093f\u0924\u093e\u092c, course, mentor\n3. \u0928\u0947\u092a\u093e\u0932\u092e\u093e \u0924\u094d\u092f\u094b skill \u0915\u094b demand \u0939\u0947\u0930\u094d\u0928\u0941\n4. Specialist \u092c\u0928\u094d\u0928\u0941 \u2014 generalist \u0928\u0939\u094b\u0909\u0928\u0941\n\nJapan \u092e\u093e \u0928\u0947\u092a\u093e\u0932\u0940 student \u0915\u094b \u0932\u093e\u0917\u093f:\n\u2022 Japanese language specialist \u2014 high demand\n\u2022 IT specialist \u2014 Japan ma best opportunity\n\u2022 Engineering specialist \u2014 Japan ko manufacturing\n\nNepal \u092e\u093e \u0928\u0947 specialization \u092e\u0939\u0924\u094d\u0935\u092a\u0942\u0930\u094d\u0923 \u091b:\n\u2022 Hydropower specialist\n\u2022 Agriculture specialist\n\u2022 Tourism specialist\n\u2022 FinTech specialist\n\nContinuous learning = Continuous earning\u0964 \u0924\u093f\u092e\u0940\u0932\u0947 \u090f\u0909\u091f\u093e field \u092e\u093e world-class \u0939\u0941\u0928\u0941\u092a\u0930\u094d\u091b \u2014 \u0924\u092c \u0928\u0948 paisa \u0906\u092b\u0948\u0902 \u0906\u0909\u0901\u091b\u0964",B.a_n,"\u0906\u092b\u094d\u0928\u094b top 3 skills \u0932\u0947\u0916\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964 \u0915\u0941\u0928 skill \u092e\u093e \u0924\u093f\u092e\u0940 \u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e \u0930\u093e\u092e\u094d\u0930\u094b \u091b\u094c? \u0924\u094d\u092f\u0938\u092e\u093e world-class \u092c\u0928\u094d\u0928\u0947 plan \u092c\u0928\u093e\u0909\u0928\u0941\u0939\u094b\u0938\u094d\u0964","\u0915\u093e\u0920\u092e\u093e\u0921\u094c\u0902\u0915\u0940 \u092a\u094d\u0930\u093f\u092f\u093e general accountant \u0925\u093f\u0908 \u2014 NPR 25,000 \u0924\u0932\u092c\u0964 Tax specialist \u092d\u090f\u092a\u091b\u093f NPR 1.5 \u0932\u093e\u0916\u0964 Specialization \u0932\u0947 6x income \u092d\u092f\u094b\u0964 \u090f\u0909\u091f\u093e \u0928\u093f\u0930\u094d\u0923\u092f\u0932\u0947 \u091c\u0940\u0935\u0928 \u092c\u0926\u0932\u094d\u092f\u094b\u0964")
B.X1=s(["Master Mind group = collective intelligence","\u090f\u0915\u091c\u0928\u093e\u0915\u094b \u0938\u0940\u092e\u093e group \u0932\u0947 \u0924\u094b\u095c\u094d\u0928\u094d\u091b","Accountability = success rate \u092c\u095d\u094d\u091b","\u0938\u0939\u0940 \u092e\u093e\u0928\u094d\u091b\u0947\u0938\u0902\u0917 \u092c\u0938\u094d\u0928\u0941 = \u0938\u0939\u0940 \u0926\u093f\u0936\u093e\u092e\u093e \u091c\u093e\u0928\u0941","\u0928\u0947\u092a\u093e\u0932\u092e\u093e successful group \u092c\u0928\u093e\u0909\u0928 \u0938\u0915\u093f\u0928\u094d\u091b"],t.s)
B.NA=new A.cc("Lesson 5 \u2014 Master Mind Group","\u0938\u0939\u0940 \u092e\u093e\u0928\u094d\u091b\u0947\u0938\u0902\u0917 \u091c\u0941\u095c\u094d\u0928\u0941","Napoleon Hill \u0915\u094b \u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e powerful concept:\n\nMaster Mind = \u0926\u0941\u0908 \u0935\u093e \u0938\u094b\u092d\u0928\u094d\u0926\u093e \u092c\u095d\u0940 like-minded \u092e\u093e\u0928\u094d\u091b\u0947\u0939\u0930\u0942\u0915\u094b group \u091c\u0941\u0928\u0932\u0947 \u090f\u0909\u091f\u093e common goal \u0924\u0930\u092b \u0915\u093e\u092e \u0917\u0930\u094d\u091b\u0928\u094d\u0964\n\n\u0915\u093f\u0928\u092d\u0928\u0947 Master Mind \u091a\u093e\u0939\u093f\u0928\u094d\u091b?\n\u2022 \u090f\u0915\u091c\u0928\u093e\u0915\u094b brain \u0938\u0940\u092e\u093f\u0924 \u091b\n\u2022 Group \u0915\u094b collective intelligence \u090f\u0915\u091c\u0928\u093e\u092d\u0928\u094d\u0926\u093e \u0920\u0942\u0932\u094b \u0939\u0941\u0928\u094d\u091b\n\u2022 Accountability \u0930\u093e\u0916\u093f\u0928\u094d\u091b \u2014 \u090f\u0915\u0932\u0948 \u0917\u0930\u094d\u0926\u093e excuse \u0917\u0930\u093f\u0928\u094d\u091b\n\u2022 \u0906\u092a\u0938\u092e\u093e \u0938\u093f\u0915\u094d\u0928\u0947 \u0930 \u092c\u095d\u094d\u0928\u0947 \u0938\u092e\u094d\u092d\u093e\u0935\u0928\u093e\n\n\u0928\u0947\u092a\u093e\u0932\u092e\u093e Master Mind \u0915\u0938\u0930\u0940 \u092c\u0928\u093e\u0909\u0928\u0947?\n1. \u0906\u092b\u094d\u0928\u094b goal \u0938\u094d\u092a\u0937\u094d\u091f \u0917\u0930\u094d\u0928\u0941\n2. \u0924\u094d\u092f\u0938\u094d\u0924\u0948 goal \u092d\u090f\u0915\u093e 3-5 \u091c\u0928\u093e \u0916\u094b\u091c\u094d\u0928\u0941\n3. Weekly meeting \u0917\u0930\u094d\u0928\u0941 \u2014 progress share \u0917\u0930\u094d\u0928\u0941\n4. \u090f\u0915\u0932\u0948 \u091c\u093e\u0928\u094d\u0928\u0947 \u0915\u0941\u0930\u093e share \u0917\u0930\u094d\u0928\u0941\n5. \u0906\u092a\u0938\u092e\u093e encourage \u0930 challenge \u0917\u0930\u094d\u0928\u0941\n\nJapan \u092e\u093e \u0928\u0947\u092a\u093e\u0932\u0940 student \u0915\u094b \u0932\u093e\u0917\u093f:\n\u2022 Study group banaunus \u2014 Japanese, \u092a\u095d\u093e\u0908, career plan share\n\u2022 Online Nepal ma pani Master Mind group huncha\n\u2022 LinkedIn ma successful Nepali sanga judhnus\n\nYou are the average of the 5 people you spend the most time with.\n\u2014 Jim Rohn\n\n\u0924\u093f\u092e\u094d\u0930\u094b 5 \u091c\u0928\u093e \u0938\u093e\u0925\u0940\u0939\u0930\u0942 \u0915\u094b \u0939\u0947\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d \u2014 \u0924\u093f\u092e\u0940 \u0924\u094d\u092f\u0939\u0940\u0928\u0947\u091b\u094c\u0964",B.X1,"\u0906\u091c \u0928\u0948 3 \u091c\u0928\u093e like-minded \u092e\u093e\u0928\u094d\u091b\u0947\u0939\u0930\u0942\u0932\u093e\u0908 message \u0917\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964 Weekly 30 \u092e\u093f\u0928\u0947\u091f \u0906\u092a\u0938\u092e\u093e goals share \u0917\u0930\u094d\u0928\u0947 group \u092c\u0928\u093e\u0909\u0928\u0941\u0939\u094b\u0938\u094d\u0964","\u0915\u093e\u0920\u092e\u093e\u0921\u094c\u0902\u0915\u093e 4 \u091c\u0928\u093e IT students \u0932\u0947 Master Mind group \u092c\u0928\u093e\u090f\u0964 Weekly meet \u0917\u0930\u094d\u091b\u0928\u094d, project share \u0917\u0930\u094d\u091b\u0928\u094d\u0964 2 \u092c\u0930\u094d\u0937 \u092a\u091b\u093f \u091a\u093e\u0930\u0947\u0935\u091c\u0928\u0932\u0947 \u0906\u092b\u094d\u0928\u0948 startup \u0916\u094b\u0932\u0947\u0964 Group \u0932\u0947 \u0928\u0948 \u0928\u0947\u092a\u093e\u0932\u092e\u093e tech ecosystem \u092c\u0928\u093e\u092f\u094b\u0964")
B.SF=s([B.Nx,B.O2,B.Nv,B.O1,B.NA],t.XW)
B.Np=new A.iV("\u0938\u092b\u0932\u0924\u093e\u0915\u094b Psychology","Think and Grow Rich \u2014 Nepal Context","Napoleon Hill \u0915\u094b timeless wisdom \u2014 \u0928\u0947\u092a\u093e\u0932\u0940 \u0935\u093f\u0926\u094d\u092f\u093e\u0930\u094d\u0925\u0940\u0915\u094b \u0932\u093e\u0917\u093f \u0938\u094b\u091a, desire, \u0930 success \u0915\u094b \u0935\u093f\u091c\u094d\u091e\u093e\u0928\u0964","\ud83e\udde0",B.cM,B.SF)
B.UK=s(["\u0905\u0930\u0941\u0915\u094b career copy \u0928\u0917\u0930\u094d\u0928\u0941","Strength = \u0938\u0939\u091c, \u0930\u092e\u093e\u0907\u0932\u094b, \u0930\u093e\u092e\u094d\u0930\u094b result","Time bhulne kaam = real passion","IKIGAI = perfect career formula","\u0928\u0947\u092a\u093e\u0932\u092e\u093e pani unique careers \u0938\u0902\u092d\u0935 \u091b\u0928\u094d"],t.s)
B.NW=new A.cc("Lesson 1 \u2014 \u0906\u092b\u094d\u0928\u094b Strength \u0915\u0938\u0930\u0940 \u091a\u093f\u0928\u094d\u0928\u0947?","\u0924\u093f\u092e\u0940\u0932\u093e\u0908 \u0915\u0941\u0928 \u0915\u0941\u0930\u093e\u092e\u093e \u0930\u0938 \u091b?","Career \u0915\u094b \u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e \u0920\u0942\u0932\u094b \u0917\u0932\u0924\u0940:\n\n\u0905\u0930\u0941\u0932\u0947 \u0917\u0930\u0947\u0915\u094b career \u0906\u092b\u0942\u0932\u0947 \u0917\u0930\u094d\u0928\u0941\u0964\n\n\u0928\u0947\u092a\u093e\u0932\u092e\u093e \u092f\u0938\u094d\u0924\u094b \u0939\u0941\u0928\u094d\u091b:\n\u2022 Buba le engineer bhayo \u2014 chhorala pani engineer banaunus\n\u2022 Saathi le doctor padhdaichha \u2014 ma pani padhdachhu\n\u2022 \u0938\u092e\u093e\u091c\u0932\u0947 doctor, engineer, bank \u0930 pilot \u092e\u093e\u0924\u094d\u0930 \u092e\u0928\u094d\u091b\n\n\u0924\u0930 strength \u092d\u0928\u0947\u0915\u094b \u0915\u0947 \u0939\u094b?\n\nStrength = \u0924\u093f\u092e\u0940\u0932\u0947 \u0938\u0939\u091c\u0948 \u0917\u0930\u094d\u0928 \u0938\u0915\u094d\u0928\u0947, \u0930\u092e\u093e\u0907\u0932\u094b \u0932\u093e\u0917\u094d\u0928\u0947, \u0930 \u0930\u093e\u092e\u094d\u0930\u094b result \u0906\u0909\u0928\u0947 \u0915\u0941\u0930\u093e\u0964\n\nStrength identify \u0917\u0930\u094d\u0928\u0947 3 \u092a\u094d\u0930\u0936\u094d\u0928:\n\n1. \u0915\u0941\u0928 \u0915\u093e\u092e \u0917\u0930\u094d\u0926\u093e time \u092d\u0941\u0932\u093f\u0928\u094d\u091b?\n(\u0918\u0921\u093c\u0940 \u0939\u0947\u0930\u094d\u0928 \u092d\u0941\u0932\u093f\u0928\u094d\u091b \u2014 \u0924\u094d\u092f\u094b \u0928\u0948 \u0924\u094d\u092f\u094b \u0915\u093e\u092e)\n\n2. \u0915\u0941\u0928 \u0915\u093e\u092e \u0917\u0930\u094d\u0926\u093e \u0925\u0915\u093e\u0907 \u0932\u093e\u0917\u094d\u0926\u0948\u0928?\n(\u0918\u0923\u094d\u091f\u094c\u0902 \u0917\u0930\u0947\u092a\u0928\u093f \u0909\u0930\u094d\u091c\u093e \u091b \u2014 \u0924\u094d\u092f\u094b \u0928\u0948 strength)\n\n3. \u0915\u0941\u0928 \u0915\u093e\u092e\u092e\u093e \u0905\u0930\u0941\u0932\u0947 \u0938\u0932\u093e\u0939 \u092e\u093e\u0917\u094d\u091b\u0928\u094d?\n(\u0905\u0930\u0941\u0932\u0947 \u0924\u093f\u092e\u0940\u0932\u093e\u0908 expert \u092e\u093e\u0928\u094d\u091b\u0928\u094d \u2014 \u0924\u094d\u092f\u094b \u0928\u0948 \u0924\u094d\u092f\u094b field)\n\nIKIGAI concept:\n\u2022 \u0924\u093f\u092e\u0940\u0932\u0947 \u0930\u092e\u093e\u0907\u0932\u094b \u0932\u093e\u0917\u094d\u0928\u0947\n\u2022 \u0924\u093f\u092e\u0940 \u0930\u093e\u092e\u094d\u0930\u094b \u0917\u0930\u094d\u0928 \u0938\u0915\u094d\u0928\u0947\n\u2022 \u0938\u0902\u0938\u093e\u0930\u0932\u093e\u0908 \u091a\u093e\u0939\u093f\u0928\u0947\n\u2022 \u092a\u0948\u0938\u093e \u092a\u093e\u0909\u0928 \u0938\u0915\u093f\u0928\u0947\n\u2014 \u092f\u0947 \u091a\u093e\u0930\u0947\u091f\u0948\u0915\u094b \u092e\u093f\u0932\u0928 \u092d\u090f\u0915\u094b \u0920\u093e\u0909\u0901 \u0928\u0948 \u0924\u094d\u092f\u094b \u0924\u093f\u092e\u094d\u0930\u094b ideal career \u0939\u094b\u0964",B.UK,"\u0906\u091c \u090f\u0909\u091f\u093e \u0915\u093e\u0917\u091c\u092e\u093e \u0932\u0947\u0916\u094d\u0928\u0941\u0939\u094b\u0938\u094d:\n1. \u0915\u0941\u0928 3 \u0915\u093e\u092e \u0917\u0930\u094d\u0926\u093e time \u092d\u0941\u0932\u093f\u0928\u094d\u091b?\n2. \u0915\u0941\u0928 3 \u0915\u093e\u092e\u092e\u093e \u0905\u0930\u0941\u0932\u0947 \u0938\u0932\u093e\u0939 \u092e\u093e\u0917\u094d\u091b\u0928\u094d?\n3. \u0915\u0941\u0928 3 \u0915\u093e\u092e \u0917\u0930\u094d\u0926\u093e \u0925\u0915\u093e\u0907 \u0932\u093e\u0917\u094d\u0926\u0948\u0928?\n\u091c\u0935\u093e\u092b \u0932\u0947\u0916\u094d\u0928\u0941 \u2014 \u0924\u094d\u092f\u0939\u0940 \u0928\u0948 \u0924\u094d\u092f\u094b strength \u0939\u094b\u0964","\u0930\u094c\u0924\u0939\u091f\u0915\u094b \u0930\u093e\u091c\u0941\u0932\u0947 \u0938\u0930\u094d\u0935\u0926\u093e coding \u0917\u0930\u094d\u0926\u093e time \u092d\u0941\u0932\u094d\u0925\u094d\u092f\u094b, \u0905\u0930\u0941\u0932\u0947 website \u092c\u0928\u093e\u0909\u0928 \u0938\u094b\u0927\u094d\u0925\u094d\u092f\u094b, \u0930\u093e\u0924 \u092d\u0930 \u0917\u0930\u0947\u092a\u0928\u093f \u0925\u0915\u094d\u0928 \u0928\u092a\u093e\u0909\u0928\u0947\u0964 Yo nai usko strength thiyo \u2014 \u0906\u091c Japan \u092e\u093e \u092a\u095d\u094d\u0926\u0948 Nepal \u0915\u094b #1 developer \u092c\u0928\u094d\u0928\u0947 \u092c\u093e\u091f\u094b\u092e\u093e \u091b\u0964")
B.Yk=s(["IT sector \u2014 Nepal ma sabai bhandaa badi growth","Freelancing \u2014 USD income, Nepal kharcha","Tourism \u2014 Nepal ko natural advantage","Agriculture \u2014 modern approach ma thulo opportunity","2026 ma AI-related jobs sabai bhandaa badi demand"],t.s)
B.NY=new A.cc("Lesson 2 \u2014 Nepal ma Career Opportunities 2026","\u0928\u0947\u092a\u093e\u0932\u092e\u093e \u0915\u0941\u0928 \u0915\u0941\u0928 career \u091b\u0928\u094d?","\u0928\u0947\u092a\u093e\u0932\u092e\u093e \u0938\u092c\u0948\u0932\u0947 \u092f\u0939\u0940 \u0920\u093e\u0928\u094d\u091b:\nDoctor, Engineer, Banker, Pilot \u2014 \u092f\u0924\u093f \u092e\u093e\u0924\u094d\u0930\u0964\n\n\u0924\u0930 2026 \u092e\u093e Nepal \u092e\u093e \u0928\u092f\u093e\u0901 emerging careers:\n\n1. IT Sector\n\u2022 Flutter/Mobile Developer \u2014 NPR 80K-3L\n\u2022 Web Developer \u2014 NPR 60K-2L\n\u2022 AI/ML Engineer \u2014 NPR 1L-5L\n\u2022 Cybersecurity \u2014 NPR 1L-4L\n\u2022 DevOps \u2014 NPR 1L-3L\n\n2. Digital Marketing\n\u2022 SEO Specialist \u2014 NPR 40K-1.5L\n\u2022 Social Media Manager \u2014 NPR 30K-1L\n\u2022 Content Creator \u2014 NPR 20K-2L\n\n3. Finance\n\u2022 Stock Market Analyst \u2014 NPR 60K-2L\n\u2022 Financial Planner \u2014 NPR 50K-1.5L\n\u2022 Crypto/FinTech \u2014 NPR 80K-3L\n\n4. Tourism/Hospitality\n\u2022 Tour Guide (specialist) \u2014 NPR 50K-3L\n\u2022 Hotel Management \u2014 NPR 40K-1.5L\n\u2022 Travel Blogger \u2014 NPR 20K-2L\n\n5. Agriculture/Environment\n\u2022 Organic Farming Expert \u2014 NPR 40K-1L\n\u2022 Hydropower Engineer \u2014 NPR 1L-4L\n\u2022 Environmental Consultant \u2014 NPR 60K-2L\n\n6. Healthcare\n\u2022 Physiotherapist \u2014 NPR 40K-1.5L\n\u2022 Mental Health Counselor \u2014 NPR 50K-2L\n\u2022 Telemedicine Doctor \u2014 NPR 1L-5L\n\n7. Education\n\u2022 Online Tutor \u2014 NPR 30K-1.5L\n\u2022 EdTech Developer \u2014 NPR 80K-3L\n\u2022 Corporate Trainer \u2014 NPR 50K-2L\n\n\u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e \u0920\u0942\u0932\u094b opportunity:\nFreelancing \u2014 Nepal ma basi foreign clients sanga kaam garnu\nUSD ma income, Nepal ma kharcha\u0964",B.Yk,"EduPath AI \u0915\u094b Govt Jobs section \u092e\u093e \u091c\u093e\u0928\u0941\u0939\u094b\u0938\u094d\u0964 \u0906\u092b\u0941\u0932\u0947 \u0930\u0941\u091a\u093e\u0909\u0928\u0947 career \u0915\u094b Nepal ma salary range \u0939\u0947\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964 \u0915\u0941\u0928 career \u092e\u093e \u0924\u093f\u092e\u094d\u0930\u094b strength match \u0917\u0930\u094d\u091b \u2014 note \u0917\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964","\u0927\u0928\u0917\u095d\u0940\u0915\u0940 \u092a\u094d\u0930\u093f\u092f\u093e\u0932\u0947 graphic design \u0930\u092e\u093e\u0907\u0932\u094b \u0932\u093e\u0917\u094d\u0925\u094d\u092f\u094b\u0964 Fiverr ma profile banaayi \u2014 \u092a\u0939\u093f\u0932\u094b \u0935\u0930\u094d\u0937 USD 500, \u0926\u094b\u0938\u094d\u0930\u094b \u0935\u0930\u094d\u0937 USD 3,000 monthly\u0964 Nepal \u092e\u093e \u092c\u0938\u093f \u0935\u093f\u0926\u0947\u0936\u0940 \u0915\u092e\u093e\u0908\u0964")
B.UH=s(["Vision \u0938\u094d\u092a\u0937\u094d\u091f \u0928\u092d\u090f \u0930\u094b\u0921\u092e\u094d\u092f\u093e\u092a \u092c\u0928\u094d\u0926\u0948\u0928","Gap analysis \u2014 k chha, k chainchha","Year by year action plan banaunus","Flexible rakhu \u2014 rigid nabanus","\u0928\u0947\u092a\u093e\u0932\u092e\u093e IT career \u2014 5 \u0935\u0930\u094d\u0937\u092e\u093e NPR 5L+ \u0938\u0902\u092d\u0935"],t.s)
B.NK=new A.cc("Lesson 3 \u2014 Career Roadmap Kasari Banauney?","\u0932\u0915\u094d\u0937\u094d\u092f\u0926\u0947\u0916\u093f \u092c\u093e\u091f\u094b \u092c\u0928\u093e\u0909\u0928\u0941","Career roadmap \u092d\u0928\u0947\u0915\u094b \u0915\u0947 \u0939\u094b?\n\n\u0924\u093f\u092e\u0940 \u0915\u0939\u093e\u0901 \u091c\u093e\u0928 \u091a\u093e\u0939\u0928\u094d\u091b\u094c, \u0915\u0938\u0930\u0940 \u091c\u093e\u0928\u0947, \u0915\u0924\u093f \u0926\u093f\u0928\u092e\u093e \u091c\u093e\u0928\u0947 \u2014 \u092f\u094b \u0928\u0948 roadmap \u0939\u094b\u0964\n\nCareer Roadmap \u0915\u0947 \u0939\u0941\u0928\u094d\u091b?\n\nStep 1: VISION \u2014 5 \u0935\u0930\u094d\u0937 \u092a\u091b\u093f \u0915\u0939\u093e\u0901 \u0939\u0941\u0928\u094d\u091b\u0941?\n\u2022 Position ke hunchha?\n\u2022 Income kati hunchha?\n\u2022 Lifestyle kastos hunchha?\n\nStep 2: CURRENT REALITY \u2014 Abhi kaha chhu?\n\u2022 Skills ke chhan?\n\u2022 Experience kati chha?\n\u2022 Network kastos chha?\n\nStep 3: GAP ANALYSIS \u2014 K chainchha?\n\u2022 Kun skills add garnu parchha?\n\u2022 Kun experience linu parchha?\n\u2022 Kun certifications chainchhan?\n\nStep 4: ACTION PLAN \u2014 Kasari pugne?\n\u2022 Year 1: Foundation \u2014 skills build\n\u2022 Year 2: Experience \u2014 projects, internship\n\u2022 Year 3: Growth \u2014 senior role/business\n\u2022 Year 4-5: Leadership/Expert\n\nNepal ma IT career roadmap example:\nAbhi: +2 pass, basic coding\nYear 1: Flutter course, 2-3 projects\nYear 2: Freelance clients, NPR 30-50K\nYear 3: Senior developer, NPR 80K-1L\nYear 4: Tech Lead ya startup, NPR 2L+\nYear 5: CTO ya founder, NPR 5L+\n\n\u092e\u0939\u0924\u094d\u0935\u092a\u0942\u0930\u094d\u0923 \u0915\u0941\u0930\u093e:\nRoadmap flexible \u0939\u0941\u0928\u0941 \u092a\u0930\u094d\u091b \u2014 \u092a\u0930\u093f\u0938\u094d\u0925\u093f\u0924\u093f \u0905\u0928\u0941\u0938\u093e\u0930 update \u0917\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964 \u0924\u0930 direction clear \u0939\u0941\u0928\u0941 \u092a\u0930\u094d\u091b\u0964",B.UH,"\u0906\u091c \u0928\u0948 \u0906\u092b\u094d\u0928\u094b 5 \u0935\u0930\u094d\u0937\u0915\u094b career roadmap \u0932\u0947\u0916\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964 Vision, current reality, gap, \u0930 action plan \u2014 \u091a\u093e\u0930\u0947\u091f\u0948 section \u092c\u0928\u093e\u0909\u0928\u0941\u0939\u094b\u0938\u094d\u0964","\u0915\u093e\u0920\u092e\u093e\u0921\u094c\u0902\u0915\u094b \u0938\u0902\u091c\u092f\u0932\u0947 22 \u0935\u0930\u094d\u0937\u092e\u093e roadmap \u092c\u0928\u093e\u092f\u094b\u0964 25 \u092e\u093e senior developer, 28 \u092e\u093e tech startup, 30 \u092e\u093e CTO\u0964 \u0905\u092c 27 \u0935\u0930\u094d\u0937\u092e\u093e \u0909 exactly \u0924\u094d\u092f\u094b plan \u092e\u093e \u091b \u2014 roadmap \u0932\u0947 \u0928\u0948 \u0915\u093e\u092e \u0917\u0930\u094d\u092f\u094b\u0964")
B.WR=s(["Fiverr \u2014 beginners ko lagi best platform","Flutter \u2014 Nepal bata sabai bhandaa badi demand","Payoneer \u2014 Nepal ma payment receive garne best way","First 3 months gaharo \u2014 persist garnu","Reviews nai freelancing ko currency ho"],t.s)
B.NN=new A.cc("Lesson 4 \u2014 Freelancing \u0930 Remote Work","\u0918\u0930\u092e\u093e \u092c\u0938\u093f \u0935\u093f\u0926\u0947\u0936\u0940 \u0915\u092e\u093e\u0907","\u0928\u0947\u092a\u093e\u0932\u0940 \u0935\u093f\u0926\u094d\u092f\u093e\u0930\u094d\u0925\u0940\u0915\u094b \u0932\u093e\u0917\u093f \u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e \u0920\u0942\u0932\u094b opportunity:\n\nNepal \u092e\u093e \u092c\u0938\u093f USD \u092e\u093e \u0915\u092e\u093e\u0909\u0928\u0941\u0964\n\nTop Freelancing Platforms:\n\n1. Fiverr\n\u2022 Beginners ko lagi best\n\u2022 Gig-based: timi service define garcha\n\u2022 Popular: graphic design, writing, coding\n\u2022 Nepal bata success rate: high\n\n2. Upwork\n\u2022 Long-term projects\n\u2022 Higher rates: USD 15-100/hour\n\u2022 Proposal likhnu parchha\n\u2022 IT, writing, marketing\n\n3. Toptal\n\u2022 Top 3% developers matra\n\u2022 USD 50-200/hour\n\u2022 Strict screening\n\n4. LinkedIn\n\u2022 Professional network\n\u2022 Direct client hunting\n\u2022 Nepal bata international clients\n\nNepal bata in-demand skills:\n\u2022 Flutter development \u2014 USD 20-80/hour\n\u2022 React/Web development \u2014 USD 15-60/hour\n\u2022 Graphic Design \u2014 USD 10-50/hour\n\u2022 Content Writing \u2014 USD 5-30/hour\n\u2022 Video Editing \u2014 USD 10-40/hour\n\u2022 SEO \u2014 USD 10-50/hour\n\nFreelancing suru garne steps:\n1. Ek skill choose garnu\n2. 3-5 portfolio projects banaunus\n3. Fiverr/Upwork profile banaunus\n4. First 3 months: low rate, reviews linus\n5. Reviews pachhi rate badhaunus\n\nNepal ma payment receive:\n\u2022 Payoneer \u2014 most popular Nepal ma\n\u2022 Wise \u2014 low fees\n\u2022 Direct bank transfer\n\nReality check:\nFirst 3-6 months: gaharo\n6-12 months: stable income\n1-2 years: NPR 1-3L monthly possible",B.WR,"\u0906\u091c \u0928\u0948 Fiverr ma account banaunus\u0964 \u0906\u092b\u094d\u0928\u094b best skill \u091b\u093e\u0928\u094d\u0928\u0941\u0939\u094b\u0938\u094d\u0964 Ek portfolio project complete garnus \u2014 \u0924\u094d\u092f\u0938\u0932\u093e\u0908 gig ma halnus\u0964","\u092a\u094b\u0916\u0930\u093e\u0915\u094b \u0930\u094b\u0936\u0928\u0932\u0947 Flutter development Fiverr ma suru garyo\u0964 Pahilo 2 mahina: NPR 15,000\n6 mahina pachhi: NPR 80,000\n1 barsha pachhi: NPR 2,00,000 monthly\u0964 Nepal ma basi Japan ko client sanga kaam garirako chha\u0964")
