B.NV=new A.cc("Lesson 5 \u2014 Identity-Based Habits","\u0924\u093f\u092e\u0940 \u0915\u0938\u094d\u0924\u094b \u092e\u093e\u0928\u094d\u091b\u0947 \u0939\u094b, \u0924\u0924\u094d\u0915\u0948 \u092c\u0928\u094d\u091b\u094c\u0938\u094d","Atomic Habits \u0915\u094b \u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e \u0917\u0939\u093f\u0930\u094b lesson:\n\n\u0924\u094d\u092f\u0938\u094d\u0924\u093e \u0939\u0941\u0928\u0941\u0939\u094b\u0938\u094d \u091c\u0938\u094d\u0924\u094b \u0924\u093f\u092e\u0940 \u092c\u0928\u094d\u0928 \u091a\u093e\u0939\u0928\u094d\u0909\u0939\u0941\u0928\u094d\u091b\u094c\u0964\n\n\u0924\u093f\u0928 \u0924\u0939 \u0915\u094b habit change:\n\n\u0924\u0939 1: OUTCOMES \u092c\u0926\u0932\u094d\u0928\u0941 \u2014 \u0928\u0924\u093f\u091c\u093e (weight lose, paisa kamaunu)\n\u0924\u0939 2: PROCESS \u092c\u0926\u0932\u094d\u0928\u0941 \u2014 system ra habit\n\u0924\u0939 3: IDENTITY \u092c\u0926\u0932\u094d\u0928\u0941 \u2014 \u0924\u093f\u092e\u0940 \u0915\u0938\u094d\u0924\u094b \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u0939\u094b\u0938\u094d\n\n\u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e powerful = Identity change\n\n\u0909\u0926\u093e\u0939\u0930\u0923:\nOutcome: \u092e\u0948\u0932\u0947 IELTS \u092e\u093e 7.0 \u0932\u094d\u092f\u093e\u0909\u0928\u0941 \u091b\u0964\nProcess: \u092e\u0948\u0932\u0947 daily 30 \u092e\u093f\u0928\u0947\u091f English \u092a\u095d\u094d\u091b\u0941\u0964\nIdentity: \u092e\u0948 \u090f\u0915\u091c\u0928\u093e English learner \u0939\u0941\u0901\u0964\n\n\u0928\u0947\u092a\u093e\u0932 context:\n\u201c\u092e\u0948 \u0924\u092e\u094d\u092c\u093e\u0915\u0941 \u091b\u094b\u095c\u094d\u0928 \u0938\u0915\u094d\u0926\u093f\u0928\u0981\u201d \u2014 Outcome-based thinking\n\u201c\u092e\u0948 \u0924\u092e\u094d\u092c\u093e\u0915\u0941 \u0928\u0916\u093e\u0928\u0947 \u092e\u093e\u0928\u094d\u091b\u0947 \u0939\u0941\u0901\u201d \u2014 Identity-based thinking\n\nIdentity \u092c\u0926\u0932\u093f\u092f\u094b \u092d\u0928\u0947 habit \u0906\u092b\u0948\u0902 \u092c\u0926\u0932\u093f\u0928\u0947\u091b\u0964\n\nPractical steps:\n1. \u0928\u093f\u0928\u094d\u092f\u093e\u0909 \u2014 \u092e\u0948 \u0915\u0938\u094d\u0924\u094b \u092e\u093e\u0928\u094d\u091b\u0947 \u0939\u0941\u0928 \u091a\u093e\u0939\u0928\u094d\u091b\u0941?\n2. \u0924\u094d\u092f\u094b identity \u0932\u0947 \u0915\u0938\u094d\u0924\u094b \u0917\u0930\u094d\u0926\u094b?\n3. \u0924\u094d\u092f\u0938\u094d\u0924\u0948 \u0917\u0930\u094d\u0928 \u0938\u0941\u0930\u0941 \u0917\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d",B.YX,"\u0906\u091c \u090f\u0909\u091f\u093e \u0915\u093e\u0917\u091c\u092e\u093e \u0932\u0947\u0916\u094d\u0928\u0941\u0939\u094b\u0938\u094d: \u201c\u092e\u0948 \u090f\u0915\u091c\u0928\u093e ___ \u0939\u0941\u0901\u201d\u0964 \u0924\u094d\u092f\u094b blank \u092d\u0930\u094d\u0928\u0941\u0939\u094b\u0938\u094d \u2014 padhne manchhe, healthy manchhe, successful manchhe\u0964 \u0905\u0928\u093f \u0924\u094d\u092f\u094b identity \u0905\u0928\u0941\u0938\u093e\u0930 \u0906\u091c\u0926\u0947\u0916\u093f \u091c\u0940\u0935\u0928 \u092c\u093f\u0924\u093e\u0909\u0928\u0941\u0939\u094b\u0938\u094d\u0964","\u0915\u093e\u0920\u092e\u093e\u0921\u094c\u0902\u0915\u0940 \u0930\u0947\u0916\u093e\u0932\u0947 \u092d\u0928\u0940: \u201c\u092e\u0948 \u0938\u094d\u0935\u0938\u094d\u0925 \u092e\u093e\u0928\u094d\u091b\u0947 \u0939\u0941\u0901\u201d\u0964 \u0924\u094d\u092f\u0938\u092a\u091b\u093f \u0909\u0938\u0932\u0947 gym \u091c\u093e\u0928\u0941, healthy \u0916\u093e\u0928\u0941, \u0930\u093e\u0924 \u091b\u093f\u091f\u094b \u0938\u0941\u0924\u094d\u0928\u0941 \u0938\u094d\u0935\u093e\u092d\u093e\u0935\u093f\u0915 \u092d\u092f\u094b\u0964 Identity \u0928\u0948 \u0938\u0902\u092a\u0942\u0930\u094d\u0923 \u091c\u0940\u0935\u0928 \u092c\u0926\u0932\u094d\u092f\u094b\u0964")
