B.UU=s(["\u0938\u093f\u0921\u094d\u0928\u0940 \u0913\u092a\u0947\u0930\u093e \u0939\u093e\u0909\u0938 \u2014 UNESCO \u0935\u093f\u0936\u094d\u0935 \u0938\u092e\u094d\u092a\u0926\u093e \u0968\u0966\u0966\u096d","\u0917\u094d\u0930\u0947\u091f \u092c\u094d\u092f\u093e\u0930\u093f\u092f\u0930 \u0930\u093f\u092b \u2014 \u0935\u093f\u0936\u094d\u0935\u0915\u094b \u0938\u092c\u0948\u092d\u0928\u094d\u0926\u093e \u0920\u0942\u0932\u094b \u092a\u094d\u0930\u0935\u093e\u0932 \u092d\u093f\u0924\u094d\u0924\u0940 (UNESCO)","\u0909\u0932\u0941\u0930\u0941-\u0915\u093e\u091f\u093e \u0924\u091c\u0941\u0924\u093e \u2014 UNESCO, \u0906\u0926\u093f\u0935\u093e\u0938\u0940 \u092a\u0935\u093f\u0924\u094d\u0930 \u0938\u094d\u0925\u0932","\u0917\u094d\u0930\u0947\u091f \u0913\u0938\u093f\u092f\u0928 \u0930\u094b\u0921 \u2014 \u0967\u0968 \u0905\u092a\u094b\u0938\u094d\u091f\u0932, \u0935\u093f\u0915\u094d\u091f\u094b\u0930\u093f\u092f\u093e","\u0921\u0947\u0928\u094d\u091f\u094d\u0930\u0940 \u0935\u0930\u094d\u0937\u093e\u0935\u0928 \u2014 \u0935\u093f\u0936\u094d\u0935\u0915\u094b \u092a\u0941\u0930\u093e\u0928\u094b \u0909\u0937\u094d\u0923\u0915\u091f\u093f\u092c\u0928\u094d\u0927\u0940\u092f \u0935\u0928 (UNESCO)","\u092c\u0928\u094d\u0921\u0940 \u092c\u093f\u091a \u2014 \u0938\u093f\u0921\u094d\u0928\u0940\u0915\u094b \u092a\u094d\u0930\u0938\u093f\u0926\u094d\u0927 \u0938\u092e\u0941\u0926\u094d\u0930\u0940 \u0915\u093f\u0928\u093e\u0930\u093e","\u0915\u093e\u0915\u093e\u0921\u0941 \u0930\u093e\u0937\u094d\u091f\u094d\u0930\u093f\u092f \u0909\u0926\u094d\u092f\u093e\u0928 \u2014 UNESCO, NT","\u092c\u094d\u0932\u0941 \u092e\u093e\u0909\u0928\u094d\u091f\u0947\u0928\u094d\u0938 \u2014 UNESCO, NSW"],t.s)
